// Находим строки: загружено, контент не готов, 1-3 часа до публикации, напоминание ещё не отправлено
const now = Date.now();
const in1h = now + 60 * 60 * 1000;
const in3h = now + 3 * 60 * 60 * 1000;
const results = [];

for (const item of $input.all()) {
  const row = item.json;
  if (row.status !== 'uploaded') continue;
  if (!row.scheduled_at) continue;
  // Идемпотентность: если напоминание уже отправлено — пропускаем
  if (row.reminded_at && String(row.reminded_at).trim() !== '') continue;

  const iso = String(row.scheduled_at).trim().replace(' ', 'T') + ':00+03:00';
  const scheduled = new Date(iso).getTime();
  if (isNaN(scheduled)) continue;
  if (scheduled < in1h || scheduled > in3h) continue;

  results.push({ json: row });
}

return results;

// Фильтруем по youtube_id из query-параметра webhook.
// Всегда возвращаем ровно один item, чтобы Respond Lookup сработал даже на пустом результате.
const query = $('🔌 Webhook: Lookup').item.json.query || {};
const youtubeId = String(query.youtube_id || '').trim();

if (!youtubeId) {
  return [{ json: { found: false, row: null, error: 'youtube_id query param missing' } }];
}

const rows = $input.all().map(i => i.json).filter(r => r && typeof r === 'object');
const match = rows.find(r => String(r.youtube_id || '').trim() === youtubeId);

return [{ json: { found: !!match, row: match || null } }];

// Webhook body приходит вложенным в $json.body.
// Распаковываем в плоский item, чтобы Google Sheets autoMapInputData
// корректно смапил поля (youtube_id, tg_text, status и т.д.) в колонки.
const results = [];
for (const item of $input.all()) {
  const body = item.json && item.json.body ? item.json.body : item.json || {};
  if (!body.youtube_id) {
    throw new Error('youtube_id отсутствует в теле запроса');
  }
  results.push({ json: body });
}
return results;

