// Парсим имя файла для метаданных YouTube + scheduled publishing
// Формат А (scheduled): "YYYY-MM-DD-HHMM ## Title ## Description ## Category.mp4"
// Формат Б (immediate): "Title ## Description ## Category.mp4" или "Title.mp4"

const inputItems = $input.all();
const results = [];

for (const item of inputItems) {
  const fileName = item.json.name || item.json.originalFilename || 'Без названия';
  const nameWithoutExt = fileName.replace(/\.[^.]+$/, '');

  let scheduledAt = null;      // ISO UTC для YouTube publishAt
  let scheduledAtMsk = null;   // Human-readable MSK для Sheets и Telegram
  let workingName = nameWithoutExt;

  // Regex: YYYY-MM-DD-HHMM в начале, затем ##
  const dateMatch = workingName.match(/^(\d{4})-(\d{2})-(\d{2})-(\d{2})(\d{2})\s*##\s*(.+)$/);
  if (dateMatch) {
    const [, yyyy, mm, dd, hh, mi, rest] = dateMatch;
    // Если prefix есть — дата-часть всегда съедается, чтобы title не содержал timestamp.
    // Даже при откате на immediate (дата в прошлом / < now+15min) парсим остаток.
    workingName = rest;

    const iso = `${yyyy}-${mm}-${dd}T${hh}:${mi}:00+03:00`;
    const scheduled = new Date(iso);
    const now = new Date();
    const minFuture = new Date(now.getTime() + 15 * 60 * 1000);

    if (!isNaN(scheduled.getTime()) && scheduled >= minFuture) {
      scheduledAt = scheduled.toISOString();
      scheduledAtMsk = `${yyyy}-${mm}-${dd} ${hh}:${mi}`;
    }
    // Если дата в прошлом или невалидна — scheduledAt остаётся null (immediate),
    // но workingName уже очищен от prefix выше.
  }

  const parts = workingName.split('##').map(s => s.trim());
  const title = parts[0] || 'Без названия';
  const description = parts[1] || '';
  const category = parts[2] || '22';

  const privacyStatus = scheduledAt ? 'private' : 'public';

  results.push({
    json: {
      ...item.json,
      videoTitle: title,
      videoDescription: description,
      videoCategory: category,
      originalFileName: fileName,
      scheduledAt,
      scheduledAtMsk,
      privacyStatus,
      driveFileId: item.json.id
    },
    binary: item.binary
  });
}

return results;

// Извлекаем base64 изображение из ответа API
// и сохраняем videoTitle + scheduled-поля для последующих нод

const imageUrl = $json.choices[0].message.images[0].image_url.url;

// Разделяем data:image/png;base64, и саму base64 строку
const base64Data = imageUrl.split(',')[1];

// Определяем MIME тип
const mimeType = imageUrl.match(/data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+).*,/)[1];

// Определяем расширение файла
const extension = mimeType.includes('png') ? 'png' : 'jpg';

// Создаем имя файла
const fileName = `thumbnail_${Date.now()}.${extension}`;

// Сохраняем данные из парсинга для использования после Merge
const meta = $('📝 Парсинг метаданных5').first().json;

return {
  json: {
    fileName: fileName,
    mimeType: mimeType,
    videoTitle: meta.videoTitle,
    videoDescription: meta.videoDescription,
    scheduledAt: meta.scheduledAt,
    scheduledAtMsk: meta.scheduledAtMsk,
    driveFileId: meta.driveFileId,
    privacyStatus: meta.privacyStatus,
    success: true
  },
  binary: {
    thumbnail: {
      data: base64Data,
      mimeType: mimeType,
      fileName: fileName
    }
  }
};
